// ── UI wiring: showTab, getLegplanRows, checkHSCodes, toggleHSMeasures ──────
// ── Tab switching ──────────────────────────────────────────────────────────
function showTab(tab, el) {
  document.querySelectorAll('.tab-chip').forEach(c => c.className = 'tab-chip');
  document.getElementById('legplan-wrap').classList.toggle('visible', tab === 'legplan');
  document.getElementById('cipl-wrap').classList.toggle('visible', tab === 'cipl');
  el.classList.add(tab === 'legplan' ? 'active-legplan' : 'active-cipl');
  if (tab === 'cipl') initCIPL();
}

// ── getLegplanRows: override from the shared JS (uses allRows) ─────────────
// Filter: BL# leeg · Kol Z niet "not received yet" (tenzij toggle aan)
function getLegplanRows() {
  const inclNRY = document.getElementById('toggle-nry')?.checked ?? false;
  return allRows.filter(r => {
    const alBlank = !r.colAL || r.colAL.trim() === '';
    if (!alBlank) return false;
    const zVal  = (r.colZ||'').trim().toLowerCase();
    const isNRY = zVal === 'not received yet' || zVal === '';
    if (isNRY && !inclNRY) return false;
    return true;
  });
}

// ── CIPL: override initCIPL to work with moederFile ───────────────────────
// ── HS Measures slide-down via douane.nl API ──────────────────────────────
async function toggleHSMeasures(hsCode, trEl) {
  const cleanCode = (hsCode || '').replace(/\s+/g, '').trim();
  if (!cleanCode) return;

  // Toggle if expansion row already exists
  let expandRow = trEl.nextElementSibling;
  if (expandRow && expandRow.classList.contains('hs-measures-row')) {
    const panel = expandRow.querySelector('.hs-measures-panel');
    if (panel.classList.contains('open')) {
      panel.classList.remove('open');
      setTimeout(() => { if (expandRow.parentNode) expandRow.remove(); }, 350);
    } else {
      panel.classList.add('open');
    }
    return;
  }

  // Create expansion row
  const colCount = trEl.cells.length;
  expandRow = document.createElement('tr');
  expandRow.className = 'hs-measures-row';
  const td = document.createElement('td');
  td.colSpan = colCount;
  td.innerHTML = `<div class="hs-measures-panel">
    <div class="hs-measures-inner hs-loading">
      <span style="color:var(--muted)">⏳ Douanemaatregelen ophalen voor <strong>${esc(cleanCode)}</strong>…</span>
    </div></div>`;
  expandRow.appendChild(td);
  trEl.insertAdjacentElement('afterend', expandRow);
  requestAnimationFrame(() => td.querySelector('.hs-measures-panel').classList.add('open'));

  const date    = document.getElementById('cipl-check-date')?.value || new Date().toISOString().slice(0,10);
  const country = document.getElementById('cipl-country-sel')?.value || '';
  const pageUrl = `https://tarief.douane.nl/ite-tariff-public/#/taric/measure/mcc/search`
    + `?sd=${date}&d=E&cc=${cleanCode}${country?`&co=${country}`:''}&cu=EUR&l=nl`;

  // Exact endpoint confirmed via browser DevTools
  const base   = `https://tarief.douane.nl/ite-tariff-public-proxy/ite-tariff-trusted-rs/v1/mcc/measures`;
  const params = `count=50&offset=0&sortorder=A&simulationdate=${encodeURIComponent(date)}&tradedirection=E&commoditycode=${encodeURIComponent(cleanCode)}&currency=EUR`;
  const apiUrl = `${base}?${params}`;

  // ── Cloudflare Worker proxy (own server — no CORS issues) ────────────────
  // Worker URL: https://douane-proxy.JOUW-NAAM.workers.dev
  // Vervang de waarde hieronder met jouw eigen worker URL na deployment.
  const WORKER_URL = 'https://douane-proxy.ks-moerlie.workers.dev';
  const workerUrl  = `${WORKER_URL}?${params}`;

  const candidates = [
    { url: workerUrl, parse: r => r.json(), label: 'cloudflare-worker' },
    { url: apiUrl,    parse: r => r.json(), label: 'direct (fallback)' },
  ];

  let lastErr = '', lastUrl = apiUrl;
  for (const { url: fetchUrl, parse, label } of candidates) {
    try {
      const resp = await fetch(fetchUrl, {
        headers: { 'Accept': 'application/json', 'Accept-Language': 'nl' }
      });
      if (!resp.ok) { lastErr = `HTTP ${resp.status} (${label})`; lastUrl = fetchUrl; continue; }
      const data = await parse(resp).catch(e => { throw new Error(`JSON parse: ${e.message}`); });
      if (!data || typeof data !== 'object') { lastErr = `Ongeldig JSON (${label})`; continue; }

      // Filter items by chosen country client-side:
      // Always show ERGA OMNES (1011 = all countries) + measures for the selected country
      if (country && Array.isArray(data.items)) {
        const sel = country.toUpperCase();
        data._allItems = data.items;
        data.items = data.items.filter(m => {
          const geo = (m.geographicalArea?.id || '').toUpperCase();
          return geo === '1011' || geo === sel;
        });
      }

      const inner = td.querySelector('.hs-measures-inner');
      inner.outerHTML = renderHSMeasures(data, country, cleanCode, date, pageUrl);
      td.querySelector('.hs-measures-panel').style.maxHeight = 'none';
      return;
    } catch (err) {
      lastErr = `${err.message} (${label})`; lastUrl = fetchUrl;
    }
  }

  // Both failed
  td.querySelector('.hs-measures-inner').outerHTML =
    `<div class="hs-measures-inner hs-loading">
      <div style="margin-bottom:.35rem">⚠️ <strong>Kon maatregelen niet ophalen</strong> — ${esc(lastErr)}</div>
      <div style="font-size:.68rem;margin-bottom:.3rem">
        De douane.nl API is bereikbaar maar staat verzoeken van externe websites niet toe.<br>
        <a href="${pageUrl}" target="_blank" style="color:var(--teal)">↗ Bekijk de maatregelen direct op douane.nl</a>
      </div>
    </div>`;
  td.querySelector('.hs-measures-panel').style.maxHeight = 'none';
}

function renderHSMeasures(data, country, hsCode, date, pageUrl) {
  const items = data.items || [];
  // Filter out supplementary unit (type 109, series O) — not a trade restriction
  const restrictions = items.filter(m =>
    m.measureType?.id !== '109' && m.measureType?.series !== 'O'
  );
  const suppUnit = items.find(m => m.measureType?.id === '109');
  const narNote  = suppUnit
    ? `<span style="font-size:.65rem;color:var(--muted)"> · 🌍 Aanvullende eenheid: <strong>${esc(suppUnit.dutyExpressions?.nl || 'Aantal stuks')}</strong> · ${esc(suppUnit.regulation?.id||'')} · ${suppUnit.startDate||''}</span>`
    : '';

  // Code description (short)
  const rawDesc = data.commodityCodeHead?.commodityCodeDescriptions?.nl || '';
  const shortDesc = rawDesc.replace(/<br\/?>/g,' ').replace(/<[^>]+>/g,'').split(';').pop().trim().slice(0,120);

  const link = `<a href="${pageUrl}" target="_blank" style="color:var(--teal);font-size:.62rem;margin-left:auto;white-space:nowrap">Bekijk op douane.nl ↗</a>`;

  if (restrictions.length === 0) {
    // ── GREEN: no restrictions ──
    return `<div class="hs-measures-inner hs-clean">
      <div style="display:flex;align-items:center;flex-wrap:wrap;gap:.5rem">
        <span>✅ <strong>Geen beperkingen</strong> voor uitvoer naar <strong>${esc(country)}</strong>${narNote}</span>
        ${link}
      </div>
      ${shortDesc ? `<div style="color:var(--muted);font-size:.62rem;margin-top:.25rem">${esc(shortDesc)}</div>` : ''}
    </div>`;
  }

  // ── RED: restrictions found ──
  const rows = restrictions.map(m => {
    const typeNl  = m.measureType?.descriptions?.nl || m.measureType?.descriptions?.en || '';
    const geo     = m.geographicalArea?.descriptions?.nl || m.geographicalArea?.id || '';
    const regId   = m.regulation?.id || '';
    const start   = m.startDate || '';
    const isProh  = /verbod|prohibition/i.test(typeNl);
    const badgeCls = isProh ? 'prohibition' : 'control';
    const badgeLbl = isProh ? '⛔ VERBOD' : '⚠️ CONTROLE';
    return `<div class="hs-measure-item">
      <span class="hs-m-badge ${badgeCls}">${badgeLbl}</span>
      <span class="hs-m-geo">${esc(geo)}</span>
      <span style="color:var(--muted)">${esc(typeNl)}</span>
      <span class="hs-m-reg">${esc(regId)} · ${esc(start)}</span>
    </div>`;
  }).join('');

  return `<div class="hs-measures-inner hs-restricted">
    <div style="display:flex;align-items:center;flex-wrap:wrap;gap:.5rem;margin-bottom:.4rem">
      <span style="color:#ef4444;font-weight:700">⛔ ${restrictions.length} maatregel(en) voor HS ${esc(hsCode)}</span>
      ${narNote}
      ${link}
    </div>
    ${rows}
    ${shortDesc ? `<div style="color:var(--muted);font-size:.62rem;margin-top:.4rem">${esc(shortDesc)}</div>` : ''}
  </div>`;
}

