async function checkHSCodes() {
  const btn  = document.getElementById('btn-hs-check');
  const date = document.getElementById('cipl-check-date')?.value
             || new Date().toISOString().slice(0,10);

  const cells = document.querySelectorAll('td.hs-cell');
  if (!cells.length) { alert('Laad eerst een CIPL shipment.'); return; }

  btn.disabled = true;
  btn.textContent = '⏳ Controleren…';

  let valid = 0, invalid = 0;
  const seen = new Set();

  cells.forEach(cell => {
    const raw    = (cell.dataset.hs || '').replace(/\s+/g, '').trim();
    const row    = cell.closest('tr');
    const sc     = row.querySelector('td.hs-status');
    const pageUrl = `https://tarief.douane.nl/ite-tariff-public/#/taric/nomenclature/sbn`
      + `?sd=${date}&d=I&cc=${encodeURIComponent(raw)}&l=nl&ql=nl`;

    row.classList.remove('hs-valid', 'hs-invalid', 'hs-checking', 'hs-manual');

    // Exact match only — a partial prefix match (e.g. 6-digit heading) does NOT
    // mean the full 8/10-digit code is valid in the CN nomenclatuur.
    const found = GN_CODES.has(raw);

    if (found) {
      valid++;
      row.classList.add('hs-valid');
      if (sc) sc.innerHTML =
        `<a class="hs-link" href="${pageUrl}" target="_blank"
           style="color:#22c55e" title="Gevonden in GN-nomenclatuur 2025/1926 — klik voor douane.nl">✓</a>`;
    } else {
      invalid++;
      row.classList.add('hs-invalid');
      if (sc) sc.innerHTML =
        `<a class="hs-link" href="${pageUrl}" target="_blank"
           style="color:#ef4444" title="NIET gevonden in GN-nomenclatuur 2025/1926 — klik voor douane.nl">✗</a>`;
    }
  });

  // Samenvatting
  const statsEl = document.getElementById('cipl-stats');
  if (statsEl) {
    statsEl.innerHTML = statsEl.innerHTML.replace(/ · <span[^>]*>.*?<\/span>/g, '');
    let msg = '';
    if (invalid > 0) {
      msg += ` · <span style="color:#ef4444"><strong>${invalid}</strong> HS code(s) NIET gevonden in GN ✗</span>`;
    }
    if (valid > 0) {
      msg += ` · <span style="color:#22c55e"><strong>${valid}</strong> geldig ✓</span>`;
    }
    msg += ` · <span style="color:var(--muted);font-size:.6rem">Bron: GN-nomenclatuur 2026 (EU 2025/1926)</span>`;
    statsEl.innerHTML += msg;
  }

  btn.disabled = false;
  btn.textContent = '🔍 Controleer HS Codes';
}


function _runInitCIPL() { initCIPL(); } // compat shim — real initCIPL defined after js_block

function _initCIPLFromSheet2(mData) {
  const headers = mData.length ? Object.keys(mData[0]) : [];
  // Try 'Shipment ' (trailing space) or 'Shipment'
  const shipCol = headers.find(h => h && h.trim().toLowerCase() === 'shipment') ||
                  headers.find(h => h && h.trim().toLowerCase().startsWith('shipment'));
  if (!shipCol) {
    document.getElementById('cipl-stats').textContent =
      'Kolom "Shipment" niet gevonden in Sheet2.'; return;
  }
  const shipVals = [...new Set(
    mData.map(r => String(r[shipCol]||'').trim()).filter(Boolean)
  )].sort((a,b) => (parseFloat(a)||999)-(parseFloat(b)||999) || a.localeCompare(b));

  const sel = document.getElementById('cipl-shipment-sel');
  const prev = sel.value;
  sel.innerHTML = '<option value="">— kies shipment —</option>' +
    shipVals.map(v => `<option value="${esc(v)}">${esc(v)}</option>`).join('');
  if (prev && shipVals.includes(prev)) sel.value = prev;
  sel.dataset.shipCol   = shipCol;
  sel.dataset.useSheet2 = '1';
  renderCIPL();
}

// ── Drag-and-drop ─────────────────────────────────────────────────────────
document.querySelectorAll('.drop-zone').forEach(dz => {
  dz.addEventListener('dragover',  e => { e.preventDefault(); dz.classList.add('dragover'); });
  dz.addEventListener('dragleave', () => dz.classList.remove('dragover'));
  dz.addEventListener('drop', e => {
    e.preventDefault(); dz.classList.remove('dragover');
    const input = dz.querySelector('input[type=file]');
    if (e.dataTransfer.files.length) { input.files = e.dataTransfer.files; input.dispatchEvent(new Event('change')); }
  });
});

